#include <stdio.h>
#include <signal.h>
#include <stdlib.h>

void sigint_handler(int signo) {
 printf("\nCaught SIGINT (Ctrl+C)\n");
 printf("Signal number: %d\n", signo);
}

int main() {
 struct sigaction sa;

 // Initialize sigaction structure
 sa.sa_handler = sigint_handler;
 sigemptyset(&sa.sa_mask); // No signals blocked during handler
 sa.sa_flags = 0; // No special flags

 // Set up signal handler for SIGINT
 if (sigaction(SIGINT, &sa, NULL) == -1) {
 perror("sigaction");
 exit(EXIT_FAILURE);
 }

 printf("Press Ctrl+C to trigger handler\n");
 while(1) {
 pause(); // Wait for signals
 }
 return 0;
}

#include <stdio.h>
#include <signal.h>
#include <stdlib.h>

void extended_handler(int signo, siginfo_t *info, void *context) {
 printf("Signal received: %d\n", signo);
 printf("Sender PID: %d\n", info->si_pid);
 printf("Sender UID: %d\n", info->si_uid);
 printf("Signal code: %d\n", info->si_code);
}

int main() {
 struct sigaction sa;

 sa.sa_sigaction = extended_handler; // Use extended handler
 sigemptyset(&sa.sa_mask);
 sa.sa_flags = SA_SIGINFO; // Enable siginfo_t

 if (sigaction(SIGUSR1, &sa, NULL) == -1) {
 perror("sigaction");
 exit(EXIT_FAILURE);
 }

 printf("My PID: %d\n", getpid());
 printf("Send SIGUSR1 to test\n");

 while(1) pause();
 return 0;
}

#include <stdio.h>
#include <signal.h>
#include <stdlib.h>
#include <unistd.h>

void handler_with_blocking(int signo) {
 sigset_t mask;
 sigemptyset(&mask);
 sigaddset(&mask, SIGINT); // Block SIGINT during handler
 sigprocmask(SIG_BLOCK, &mask, NULL);

 printf("Handler started - SIGINT now blocked\n");
 sleep(5); // Critical section
 printf("Handler finished\n");

 sigemptyset(&mask);
 sigprocmask(SIG_UNBLOCK, &mask, NULL); // Unblock SIGINT
}

int main() {
 struct sigaction sa;

 sa.sa_handler = handler_with_blocking;
 sigemptyset(&sa.sa_mask);
 // SIGINT will be blocked during handler due to handler logic
 sa.sa_flags = 0;

 sigaction(SIGINT, &sa, NULL);

 printf("Handler will block SIGINT for 5 seconds\n");
 while(1) pause();
 return 0;
}

#include <stdio.h>
#include <signal.h>
#include <stdlib.h>

void handler(int signo) {
 printf("Signal %d received\n", signo);
}

int main() {
 sigset_t mask, oldmask;
 struct sigaction sa;

 // Setup handler
 sa.sa_handler = handler;
 sigemptyset(&sa.sa_mask);
 sa.sa_flags = 0;
 sigaction(SIGUSR1, &sa, NULL);

 // Create signal set and add SIGUSR1
 sigemptyset(&mask);
 sigaddset(&mask, SIGUSR1);

 // Block SIGUSR1
 sigprocmask(SIG_BLOCK, &mask, &oldmask);
 printf("SIGUSR1 is now blocked\n");

 // Raise signal (will be blocked, queued)
 raise(SIGUSR1);
 printf("Signal raised but blocked\n");

 // Unblock SIGUSR1 - handler executes now
 sigprocmask(SIG_SETMASK, &oldmask, NULL);
 printf("SIGUSR1 unblocked - handler should have run\n");

 return 0;
}
